namespace sv_40a64b172810429092bc878520687b52.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

namespace sv_40a64b172810429092bc878520687b52.Services;

public static class TimeFormatter
{
    public static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

@using sv_40a64b172810429092bc878520687b52.Services

<div class="emoji-picker">
    @foreach (var emoji in _emojis)
    {
        <button class="emoji-option" @onclick="() => OnEmojiSelected.InvokeAsync(emoji)">@emoji</button>
    }
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<string> OnEmojiSelected { get; set; }

    private static readonly string[] _emojis = ["👍", "❤️", "😂", "🎉", "😮", "🚀"];
}

.emoji-picker {
    display: flex;
    gap: 4px;
    background: #2f3136;
    border: 1px solid #202225;
    border-radius: 6px;
    padding: 6px;
    margin-top: 4px;
    width: fit-content;
}

.emoji-option {
    background: none;
    border: none;
    font-size: 20px;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    line-height: 1;
}

.emoji-option:hover {
    background: #36393f;
}

.message-input {
    display: flex;
    gap: 8px;
    padding: 12px 20px 20px;
    flex-shrink: 0;
}

.message-input textarea {
    flex: 1;
    resize: none;
    border: none;
    border-radius: 8px;
    padding: 10px 14px;
    font-size: 15px;
    background: #40444b;
    color: #dcddde;
    font-family: inherit;
    min-height: 44px;
    max-height: 120px;
}

.message-input textarea::placeholder {
    color: #72767d;
}

.message-input textarea:focus {
    outline: none;
}

.send-btn {
    padding: 0 20px;
    background: #5865f2;
    color: #fff;
    border: none;
    border-radius: 8px;
    font-size: 14px;
    font-weight: 600;
    cursor: pointer;
    align-self: flex-end;
    height: 44px;
}

.send-btn:hover {
    background: #4752c4;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

@using sv_40a64b172810429092bc878520687b52.Services

<div class="channel-item @(IsActive ? "active" : "")"
     @onclick="() => OnSelect.InvokeAsync(Channel.Id)">
    <div class="channel-header">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    <div class="channel-desc">@Channel.Description</div>
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnSelect { get; set; }
}

.channel-item {
    padding: 8px 16px;
    cursor: pointer;
    transition: background 0.15s;
}

.channel-item:hover {
    background: #34373c;
}

.channel-item.active {
    background: #393c43;
}

.channel-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 8px;
}

.channel-name {
    font-weight: 600;
    font-size: 15px;
    color: #dcddde;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.channel-item.active .channel-name {
    color: #fff;
}

.channel-desc {
    font-size: 12px;
    color: #8e9297;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    margin-top: 2px;
}

.unread-badge {
    background: #ed4245;
    color: #fff;
    border-radius: 10px;
    padding: 1px 6px;
    font-size: 12px;
    font-weight: 700;
    min-width: 18px;
    text-align: center;
    flex-shrink: 0;
}

@using sv_40a64b172810429092bc878520687b52.Services

<div class="message-item" @onmouseenter="() => _showActions = true" @onmouseleave="HideOverlays">
    <div class="message-header">
        <span class="author">@Message.Author</span>
        <span class="timestamp">@TimeFormatter.FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <span class="reaction-badge" title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </span>
            }
        </div>
    }

    @if (ThreadSummary is not null)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ThreadSummary.ReplyCount @(ThreadSummary.ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_showActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)" title="Reply in thread">
                💬 Reply
            </button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">
                😀 React
            </button>
        </div>
    }

    @if (_showEmojiPicker)
    {
        <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public ThreadSummary? ThreadSummary { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter, EditorRequired] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool _showActions;
    private bool _showEmojiPicker;

    private void HideOverlays()
    {
        _showActions = false;
        _showEmojiPicker = false;
    }

    private void ToggleEmojiPicker()
    {
        _showEmojiPicker = !_showEmojiPicker;
    }

    private async Task HandleEmojiSelected(string emoji)
    {
        _showEmojiPicker = false;
        _showActions = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }
}

.message-item {
    padding: 8px 12px;
    position: relative;
    border-radius: 4px;
}

.message-item:hover {
    background: #32353b;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 600;
    color: #fff;
    font-size: 15px;
}

.timestamp {
    font-size: 12px;
    color: #72767d;
}

.message-content {
    font-size: 15px;
    line-height: 1.4;
    word-wrap: break-word;
}

.reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 6px;
}

.reaction-badge {
    background: #2f3136;
    border: 1px solid #4f545c;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 13px;
    cursor: default;
}

.thread-link {
    background: none;
    border: none;
    color: #00aff4;
    font-size: 13px;
    cursor: pointer;
    padding: 4px 0;
    font-weight: 600;
    display: block;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -8px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #2f3136;
    border: 1px solid #202225;
    border-radius: 4px;
    padding: 2px;
    z-index: 1;
}

.action-btn {
    background: none;
    border: none;
    color: #b9bbbe;
    font-size: 13px;
    padding: 4px 8px;
    cursor: pointer;
    border-radius: 3px;
    white-space: nowrap;
}

.action-btn:hover {
    background: #36393f;
    color: #fff;
}

