@using sv_40a64b172810429092bc878520687b52.Services

<div class="channel-item @(IsActive ? "active" : "")"
     @onclick="() => OnSelect.InvokeAsync(Channel.Id)">
    <div class="channel-header">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    <div class="channel-desc">@Channel.Description</div>
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnSelect { get; set; }
}

.channel-item {
    padding: 8px 16px;
    cursor: pointer;
    transition: background 0.15s;
}

.channel-item:hover {
    background: #34373c;
}

.channel-item.active {
    background: #393c43;
}

.channel-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 8px;
}

.channel-name {
    font-weight: 600;
    font-size: 15px;
    color: #dcddde;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.channel-item.active .channel-name {
    color: #fff;
}

.channel-desc {
    font-size: 12px;
    color: #8e9297;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    margin-top: 2px;
}

.unread-badge {
    background: #ed4245;
    color: #fff;
    border-radius: 10px;
    padding: 1px 6px;
    font-size: 12px;
    font-weight: 700;
    min-width: 18px;
    text-align: center;
    flex-shrink: 0;
}

