arguments.file_text:
@using sv_40a64b172810429092bc878520687b52.Services

<div class="channel-list">
    <h3 class="channel-list-title">Channels</h3>
    @foreach (var channel in Channels)
    {
        <ChannelItem Channel="channel"
                     IsActive="channel.Id == SelectedChannelId"
                     OnSelect="OnChannelSelected" />
    }
</div>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = new();
    [Parameter] public int? SelectedChannelId { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-list {
    width: 260px;
    min-width: 220px;
    background: #2c2f33;
    color: #dcddde;
    padding: 16px 0;
    overflow-y: auto;
    border-right: 1px solid #202225;
    flex-shrink: 0;
}

.channel-list-title {
    padding: 0 16px;
    margin: 0 0 12px;
    font-size: 13px;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    color: #8e9297;
    font-weight: 700;
}

@using sv_40a64b172810429092bc878520687b52.Services

<div class="message-area">
    @if (Channel is not null)
    {
        <div class="message-area-header">
            <h2># @Channel.Name</h2>
            <p>@Channel.Description</p>
        </div>
    }

    <div class="message-list">
        @if (HasMoreMessages)
        {
            <button class="load-more" @onclick="OnLoadMore" disabled="@IsLoadingMore">
                @(IsLoadingMore ? "Loading..." : "Load older messages")
            </button>
        }

        @foreach (var msg in DisplayMessages)
        {
            <MessageItem Message="msg"
                         ThreadSummary="GetThreadSummary(msg.Id)"
                         OnOpenThread="OnOpenThread"
                         OnReact="OnReact" />
        }
    </div>

    <MessageInput OnSubmit="OnSendMessage" />
</div>

@code {
    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = new();
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = new();
    [Parameter] public bool IsThreadOpen { get; set; }
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter, EditorRequired] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter, EditorRequired] public EventCallback OnLoadMore { get; set; }

    private IEnumerable<Message> DisplayMessages =>
        Messages.Where(m => !m.ReplyToId.HasValue);

    private ThreadSummary? GetThreadSummary(int messageId) =>
        ThreadSummaries.GetValueOrDefault(messageId);
}

.message-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    background: #36393f;
    color: #dcddde;
    min-width: 0;
}

.message-area-header {
    padding: 12px 20px;
    border-bottom: 1px solid #202225;
    flex-shrink: 0;
}

.message-area-header h2 {
    margin: 0;
    font-size: 18px;
    color: #fff;
    font-weight: 700;
}

.message-area-header p {
    margin: 4px 0 0;
    font-size: 13px;
    color: #8e9297;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 16px 8px;
}

.load-more {
    display: block;
    margin: 0 auto 16px;
    padding: 6px 16px;
    background: #4f545c;
    color: #dcddde;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 13px;
}

.load-more:hover {
    background: #5d6269;
}

.load-more:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

@using sv_40a64b172810429092bc878520687b52.Services

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <div class="root-author">@RootMessage.Author</div>
            <div class="root-content">@RootMessage.Content</div>
            <div class="root-time">@TimeFormatter.FormatRelativeTime(RootMessage.SentAt)</div>
        </div>
    }

    <div class="thread-messages">
        @foreach (var msg in ThreadMessages)
        {
            <div class="thread-reply">
                <div class="reply-header">
                    <span class="reply-author">@msg.Author</span>
                    <span class="reply-time">@TimeFormatter.FormatRelativeTime(msg.SentAt)</span>
                </div>
                <div class="reply-content">@msg.Content</div>
            </div>
        }
    </div>

    <MessageInput Placeholder="Reply in thread..." ButtonText="Reply" OnSubmit="OnReply" />
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> ThreadMessages { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback OnClose { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnReply { get; set; }
}

