arguments.file_text:
@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@using sv_40a64b172810429092bc878520687b52.Services

@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelList Channels="_channels"
                 SelectedChannelId="_selectedChannelId"
                 OnChannelSelected="HandleChannelSelected" />

    <MessageArea Channel="_selectedChannel"
                 Messages="_messages"
                 ThreadSummaries="_threadSummaries"
                 IsThreadOpen="_activeThreadRootId.HasValue"
                 IsLoadingMore="_isLoadingMore"
                 HasMoreMessages="_hasMoreMessages"
                 OnOpenThread="HandleOpenThread"
                 OnReact="HandleReact"
                 OnSendMessage="HandleSendMessage"
                 OnLoadMore="HandleLoadMore" />

    @if (_activeThreadRootId.HasValue)
    {
        <ThreadPanel RootMessage="_threadRootMessage"
                     ThreadMessages="_threadMessages"
                     OnClose="HandleCloseThread"
                     OnReply="HandleReply" />
    }
</div>

@code {
    private List<Channel> _channels = new();
    private Channel? _selectedChannel;
    private int? _selectedChannelId;
    private List<Message> _messages = new();
    private Dictionary<int, ThreadSummary> _threadSummaries = new();
    private int? _activeThreadRootId;
    private Message? _threadRootMessage;
    private List<Message> _threadMessages = new();
    private bool _isLoadingMore;
    private bool _hasMoreMessages = true;
    private const int PageSize = 50;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _selectedChannelId = channelId;
        _selectedChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _hasMoreMessages = _messages.Count >= PageSize;
        BuildThreadSummaries();
        await ChatService.MarkChannelReadAsync(channelId);

        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        }
    }

    private void BuildThreadSummaries()
    {
        _threadSummaries.Clear();
        var replies = _messages.Where(m => m.ReplyToId.HasValue);
        foreach (var group in replies.GroupBy(m => m.ReplyToId!.Value))
        {
            _threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt));
        }
    }

    private async Task HandleChannelSelected(int channelId)
    {
        _activeThreadRootId = null;
        _threadRootMessage = null;
        _threadMessages.Clear();
        await SelectChannel(channelId);
    }

    private async Task HandleOpenThread(int rootMessageId)
    {
        _activeThreadRootId = rootMessageId;
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        _threadMessages = await ChatService.GetThreadAsync(rootMessageId);
    }

    private void HandleCloseThread()
    {
        _activeThreadRootId = null;
        _threadRootMessage = null;
        _threadMessages.Clear();
    }

    private async Task HandleReact((int MessageId, string Emoji) reaction)
    {
        await ChatService.AddReactionAsync(reaction.MessageId, reaction.Emoji);
        if (_selectedChannelId.HasValue)
        {
            _messages = await ChatService.GetMessagesAsync(_selectedChannelId.Value, 0, _messages.Count);
            BuildThreadSummaries();
        }
    }

    private async Task HandleSendMessage(string content)
    {
        if (_selectedChannelId.HasValue)
        {
            var msg = await ChatService.SendMessageAsync(_selectedChannelId.Value, content, null);
            _messages.Add(msg);
        }
    }

    private async Task HandleReply(string content)
    {
        if (_selectedChannelId.HasValue && _activeThreadRootId.HasValue)
        {
            var msg = await ChatService.SendMessageAsync(
                _selectedChannelId.Value, content, _activeThreadRootId.Value);
            _threadMessages.Add(msg);
            _messages.Add(msg);
            BuildThreadSummaries();
        }
    }

    private async Task HandleLoadMore()
    {
        if (_isLoadingMore || !_hasMoreMessages || !_selectedChannelId.HasValue)
            return;

        _isLoadingMore = true;
        var older = await ChatService.GetMessagesAsync(
            _selectedChannelId.Value, _messages.Count, PageSize);
        _hasMoreMessages = older.Count >= PageSize;
        _messages.InsertRange(0, older);
        BuildThreadSummaries();
        _isLoadingMore = false;
    }
}

.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    background: #36393f;
}

